use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{TodoTitle, UserId, WaitingForId, WaitingForItem, WaitingOnPerson};

struct WaitingForRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    waiting_on: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
}

impl WaitingForRecord {
    fn into_domain(self) -> WaitingForItem {
        let id = WaitingForId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");
        let waiting_on =
            WaitingOnPerson::parse(self.waiting_on).expect("stored waiting_on should be valid");

        WaitingForItem::from_parts(
            id,
            user_id,
            title,
            waiting_on,
            self.created_at,
            self.completed_at,
        )
    }
}

pub async fn insert_waiting_for_item(
    pool: &PgPool,
    item: &WaitingForItem,
) -> Result<(), sqlx::Error> {
    let completed_at: Option<&DateTime<Utc>> = match item {
        WaitingForItem::Completed { completed_at, .. } => Some(completed_at),
        WaitingForItem::Active { .. } => None,
    };

    sqlx::query!(
        r#"INSERT INTO waiting_for_items (id, user_id, title, waiting_on, created_at, completed_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz, $6 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.waiting_on().as_str(),
        item.created_at() as &DateTime<Utc>,
        completed_at as Option<&DateTime<Utc>>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_active_waiting_for_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<WaitingForItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        WaitingForRecord,
        r#"SELECT id, user_id, title, waiting_on,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM waiting_for_items
           WHERE user_id = $1 AND completed_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.into_domain()).collect())
}

pub async fn find_waiting_for_item_by_id(
    pool: &PgPool,
    item_id: &WaitingForId,
) -> Result<Option<WaitingForItem>, sqlx::Error> {
    let record: Option<WaitingForRecord> = sqlx::query_as!(
        WaitingForRecord,
        r#"SELECT id, user_id, title, waiting_on,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM waiting_for_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r| r.into_domain()))
}

pub async fn complete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    completed_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE waiting_for_items SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as &DateTime<Utc>,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM waiting_for_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_waiting_for_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM waiting_for_items WHERE user_id = $1 AND completed_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn update_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    title: &TodoTitle,
    waiting_on: &WaitingOnPerson,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE waiting_for_items SET title = $1, waiting_on = $2 WHERE id = $3"#,
        title.as_str(),
        waiting_on.as_str(),
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

use sqlx::PgPool;

use crate::domain::{
    TodoTitle, TodoTitleError, UserId, WaitingForId, WaitingForItem, WaitingOnPerson,
    WaitingOnPersonError,
};
use crate::infrastructure::waiting_for_repository;

#[derive(Debug, thiserror::Error)]
pub enum AddWaitingForError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error("Invalid waiting-on person: {0}")]
    InvalidWaitingOn(#[from] WaitingOnPersonError),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

#[tracing::instrument(
    name = "add_waiting_for_item",
    skip(pool, title, waiting_on),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn add_waiting_for_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
    waiting_on: String,
) -> Result<WaitingForItem, AddWaitingForError> {
    let title = TodoTitle::parse(title)?;
    let waiting_on = WaitingOnPerson::parse(waiting_on)?;
    let item = WaitingForItem::new(user_id, title, waiting_on);

    waiting_for_repository::insert_waiting_for_item(pool, &item)
        .await
        .map_err(|e| {
            AddWaitingForError::Unexpected(anyhow::anyhow!(
                "Failed to insert waiting-for item: {e}"
            ))
        })?;

    tracing::info!("Waiting-for item added");
    Ok(item)
}

#[tracing::instrument(
    name = "list_active_waiting_for_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn list_active_waiting_for_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<WaitingForItem>, anyhow::Error> {
    let items = waiting_for_repository::find_active_waiting_for_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch waiting-for items: {e}"))?;

    Ok(items)
}

#[tracing::instrument(
    name = "count_active_waiting_for_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn count_active_waiting_for_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, anyhow::Error> {
    let count = waiting_for_repository::count_active_waiting_for_items(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count waiting-for items: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum CompleteWaitingForError {
    #[error("Waiting-for item not found")]
    NotFound,
    #[error("Not authorized to complete this waiting-for item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "complete_waiting_for_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn complete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    user_id: &UserId,
) -> Result<(), CompleteWaitingForError> {
    let item = waiting_for_repository::find_waiting_for_item_by_id(pool, item_id)
        .await
        .map_err(|e| CompleteWaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(CompleteWaitingForError::NotFound)?;

    if item.user_id() != user_id {
        return Err(CompleteWaitingForError::Unauthorized);
    }

    let completed = item.complete();
    if let WaitingForItem::Completed { completed_at, .. } = &completed {
        waiting_for_repository::complete_waiting_for_item(pool, item_id, completed_at)
            .await
            .map_err(|e| {
                CompleteWaitingForError::Unexpected(anyhow::anyhow!(
                    "Failed to complete waiting-for item: {e}"
                ))
            })?;
    }

    tracing::info!("Waiting-for item completed");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteWaitingForError {
    #[error("Waiting-for item not found")]
    NotFound,
    #[error("Not authorized to delete this waiting-for item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_waiting_for_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    user_id: &UserId,
) -> Result<(), DeleteWaitingForError> {
    let item = waiting_for_repository::find_waiting_for_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteWaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteWaitingForError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteWaitingForError::Unauthorized);
    }

    waiting_for_repository::delete_waiting_for_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteWaitingForError::Unexpected(anyhow::anyhow!(
                "Failed to delete waiting-for item: {e}"
            ))
        })?;

    tracing::info!("Waiting-for item deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum UpdateWaitingForError {
    #[error("Waiting-for item not found")]
    NotFound,
    #[error("Not authorized to edit this waiting-for item")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(TodoTitleError),
    #[error("Invalid waiting-on person: {0}")]
    InvalidWaitingOn(WaitingOnPersonError),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

#[tracing::instrument(
    name = "update_waiting_for_item",
    skip(pool, new_title, new_waiting_on),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn update_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    user_id: &UserId,
    new_title: String,
    new_waiting_on: String,
) -> Result<(), UpdateWaitingForError> {
    let item = waiting_for_repository::find_waiting_for_item_by_id(pool, item_id)
        .await
        .map_err(|e| UpdateWaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(UpdateWaitingForError::NotFound)?;

    if item.user_id() != user_id {
        return Err(UpdateWaitingForError::Unauthorized);
    }

    let title = TodoTitle::parse(new_title).map_err(UpdateWaitingForError::InvalidTitle)?;
    let waiting_on =
        WaitingOnPerson::parse(new_waiting_on).map_err(UpdateWaitingForError::InvalidWaitingOn)?;

    waiting_for_repository::update_waiting_for_item(pool, item_id, &title, &waiting_on)
        .await
        .map_err(|e| {
            UpdateWaitingForError::Unexpected(anyhow::anyhow!(
                "Failed to update waiting-for item: {e}"
            ))
        })?;

    tracing::info!("Waiting-for item updated");
    Ok(())
}

