use axum::http::HeaderMap;
use axum::response::{Html, IntoResponse, Response};

mod auth;
mod contexts;
mod dashboard;
mod forgot_password;
mod gtd_placeholders;
mod health_check;
mod inbox;
mod index;
mod login;
mod next_actions;
mod projects;
